import{_ as s,o as t,c as a,ao as i}from"./chunks/framework.C2uOknPB.js";const k=JSON.parse('{"title":"Boundary Types","description":"","frontmatter":{},"headers":[],"relativePath":"guide/boundary-types.md","filePath":"guide/boundary-types.md","lastUpdated":null}'),n={name:"guide/boundary-types.md"};function r(l,e,o,d,h,p){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="Boundary-Types" tabindex="-1">Boundary Types <a class="header-anchor" href="#Boundary-Types" aria-label="Permalink to &quot;Boundary Types {#Boundary-Types}&quot;">​</a></h1><p>Because <code>juliac --trim</code> exposes only C-ABI functions, every argument and return value of an exported function must be a <strong>boundary type</strong> — a Julia type that ParselTongue knows how to lower to a C carrier and marshal to/from Python.</p><h2 id="Supported-types" tabindex="-1">Supported types <a class="header-anchor" href="#Supported-types" aria-label="Permalink to &quot;Supported types {#Supported-types}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Julia type</th><th style="text-align:right;">Python</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;"><code>Int8</code>–<code>Int64</code>, <code>UInt8</code>–<code>UInt64</code></td><td style="text-align:right;"><code>int</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;"><code>Bool</code></td><td style="text-align:right;"><code>bool</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;"><code>Float32</code>, <code>Float64</code></td><td style="text-align:right;"><code>float</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;"><code>ComplexF32</code>, <code>ComplexF64</code></td><td style="text-align:right;"><code>complex</code></td><td style="text-align:right;">scalars and array elements</td></tr><tr><td style="text-align:right;"><code>String</code></td><td style="text-align:right;"><code>str</code></td><td style="text-align:right;">UTF-8; see ownership below</td></tr><tr><td style="text-align:right;"><code>Array{T,N}</code> / <code>AbstractArray{T,N}</code> (numeric/complex <code>T</code>)</td><td style="text-align:right;"><code>numpy.ndarray</code> (buffer in)</td><td style="text-align:right;">zero-copy; the <em>type</em> picks the memory-order policy — see <a href="/ParselTongue.jl/dev/examples/arrays">Arrays &amp; NumPy</a></td></tr><tr><td style="text-align:right;"><code>Mut{T}</code> (argument only)</td><td style="text-align:right;">writable buffer</td><td style="text-align:right;">in-place mutation writes back to NumPy — see <a href="/ParselTongue.jl/dev/guide/boundary-types#In-place-mutation-and-void-returns">In-place</a></td></tr><tr><td style="text-align:right;"><code>Nothing</code> (return only)</td><td style="text-align:right;"><code>None</code></td><td style="text-align:right;">for <code>f!</code>-style in-place functions</td></tr><tr><td style="text-align:right;"><code>Tuple{…}</code> (return only)</td><td style="text-align:right;"><code>tuple</code></td><td style="text-align:right;">multiple return values, e.g. <code>(q, r)</code></td></tr></tbody></table><p><code>@pymodule pkg.sub begin … end</code> groups functions into a Python <strong>submodule</strong> (<code>pkg.sub</code>) over one compiled extension — see <a href="/ParselTongue.jl/dev/examples/scientific#Submodules">Submodules</a>.</p><p>A signature that uses anything else is rejected <strong>at build time</strong> with a clear message — not a cryptic trim error:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@pyfunc</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bad</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Dict{String,Int}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Int</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> length</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(d)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ERROR: ParselTongue: type \`Dict{String, Int64}\` cannot cross the Python boundary.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Missing boundary methods: c_abi_type(::Type{...}), to_c(::...), from_c(...).</span></span></code></pre></div><p>This check is a <a href="https://github.com/el_oso/TypeContracts.jl" target="_blank" rel="noreferrer">TypeContracts.jl</a> contract (<a href="/ParselTongue.jl/dev/reference/api#ParselTongue.PyBoundary"><code>PyBoundary</code></a>): the boundary protocol is registered as an interface and verified with <code>satisfies</code> before any compilation happens.</p><h2 id="Ownership-and-copies" tabindex="-1">Ownership and copies <a class="header-anchor" href="#Ownership-and-copies" aria-label="Permalink to &quot;Ownership and copies {#Ownership-and-copies}&quot;">​</a></h2><ul><li><p><strong>Strings.</strong> A <code>str</code> argument is borrowed for the duration of the call and copied into a Julia <code>String</code>. A returned <code>String</code> is copied into a freshly <code>malloc</code>&#39;d C buffer; the shim builds a Python <code>str</code> from it and frees it (Julia allocates, C frees) — no dependence on Julia GC timing.</p></li><li><p><strong>Arrays.</strong> An array argument is a zero-copy view over the Python buffer (valid for the call). A returned array is copied into a Python-owned object in natural shape. See <a href="/ParselTongue.jl/dev/examples/arrays">Arrays &amp; NumPy</a>.</p></li></ul><h2 id="N-D-arrays:-the-dual-policy" tabindex="-1">N-D arrays: the dual policy <a class="header-anchor" href="#N-D-arrays:-the-dual-policy" aria-label="Permalink to &quot;N-D arrays: the dual policy {#N-D-arrays:-the-dual-policy}&quot;">​</a></h2><p>NumPy is row-major (C order); Julia is column-major. Rather than transpose silently, the <strong>argument type</strong> you write selects the zero-copy policy:</p><ul><li><p><code>::AbstractArray{T,N}</code> (e.g. <code>AbstractMatrix{Float64}</code>) → a <strong>logical view</strong> with NumPy&#39;s shape and indexing (<code>A[i,j]</code> matches <code>a[i,j]</code>). Ideal for elementwise / indexing code. Requires C-contiguous input (the NumPy default).</p></li><li><p><code>::Array{T,N}</code> (e.g. <code>Matrix{Float64}</code>) → a dense <code>Array</code>, never copied for BLAS — but a C-order input arrives <strong>transposed</strong> (axes reversed). Pass <code>np.asfortranarray(x)</code> to get the natural shape, or do the transpose bookkeeping yourself.</p></li></ul><p>Returns always surface to NumPy in natural shape. Full worked example: <a href="/ParselTongue.jl/dev/examples/arrays">Arrays &amp; NumPy</a>.</p><h2 id="In-place-mutation-and-void-returns" tabindex="-1">In-place mutation and void returns <a class="header-anchor" href="#In-place-mutation-and-void-returns" aria-label="Permalink to &quot;In-place mutation and void returns {#In-place-mutation-and-void-returns}&quot;">​</a></h2><p>Wrap an array argument in <code>Mut{…}</code> to receive a <strong>writable</strong> view, so Julia mutations write straight back to the caller&#39;s NumPy array (no copy). Pair it with a <code>::Nothing</code> return for the idiomatic <code>f!</code> pattern:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@pyfunc</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> scale!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Mut{Vector{Float64}}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, k</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Float64</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Nothing</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.*=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> k; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">nothing</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;&gt;&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> np.array([</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]); mymod.scale(x, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); x</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">array([</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">., </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">., </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.])</span></span></code></pre></div><p><code>Mut{T}</code> is peeled to <code>T</code> for the Julia function (the body uses a plain array); it only affects how the buffer is acquired. A trailing <code>!</code> in the Julia name is dropped for the Python name (<code>scale!</code> → <code>scale</code>).</p><h2 id="Extending-the-boundary" tabindex="-1">Extending the boundary <a class="header-anchor" href="#Extending-the-boundary" aria-label="Permalink to &quot;Extending the boundary {#Extending-the-boundary}&quot;">​</a></h2><p>The boundary protocol is three functions (<a href="/ParselTongue.jl/dev/reference/api#ParselTongue.c_abi_type"><code>c_abi_type</code></a>, <a href="/ParselTongue.jl/dev/reference/api#ParselTongue.from_c"><code>from_c</code></a>, <a href="/ParselTongue.jl/dev/reference/api#ParselTongue.to_c"><code>to_c</code></a>). The <code>from_c</code>/<code>to_c</code> conversions run <strong>inside</strong> the trimmed library, so they must be trim-safe (type-stable, no dynamic dispatch). A custom boundary type looks like the built-in scalar definitions:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ParselTongue</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">c_abi_type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Type{MyInt}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Int64</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ParselTongue</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">from_c</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Type{MyInt}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Int64</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> MyInt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ParselTongue</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">to_c</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">MyInt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Int64</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">value)</span></span></code></pre></div><p>After defining all three, <code>ParselTongue.is_boundary_type(MyInt)</code> returns <code>true</code> and <code>MyInt</code> may appear in <code>@pyfunc</code> signatures.</p><p>See the <a href="/ParselTongue.jl/dev/reference/api#Boundary-type-system">API Reference</a> for the full docstrings of <a href="/ParselTongue.jl/dev/reference/api#ParselTongue.PyBoundary"><code>PyBoundary</code></a>, <a href="/ParselTongue.jl/dev/reference/api#ParselTongue.c_abi_type"><code>c_abi_type</code></a>, <a href="/ParselTongue.jl/dev/reference/api#ParselTongue.from_c"><code>from_c</code></a>, and <a href="/ParselTongue.jl/dev/reference/api#ParselTongue.to_c"><code>to_c</code></a>.</p>`,24)])])}const y=s(n,[["render",r]]);export{k as __pageData,y as default};
